//! # 图标渲染 (icon_render)
//!
//! 本模块实现玩家图标的渲染，将 [`IconResult`] 转换为 16×16 RGBA PNG 图像。
//!
//! ## 功能说明
//!
//! - **PNG 渲染** — 将图标颜色选择渲染为 PNG 字节流
//! - **Base64 编码** — 将 PNG 编码为 data URL 格式
//! - **便捷接口** — 直接从玩家名称渲染图标
//!
//! ## 渲染流程
//!
//! 复现 JS `Sgls.ts()` / `Sgls.o4()` / `Sgls.tu()` 流程：
//!
//! 1. **填充背景** — 用背景色填充内部 14×14 区域
//! 2. **合成前景** — 使用 source-over 混合模式合成每个前景形状
//! 3. **绘制边框** — 绘制深色边框覆盖层
//! 4. **应用掩码** — 应用边框不透明度掩码（直接替换 alpha 通道）
//! 5. **编码 PNG** — 编码为 16×16 RGBA PNG
//!
//! ## 精灵表
//!
//! 使用 128×128 的精灵表，包含：
//! - 38 个前景形状（每个 16×16）
//! - 8 个边框深色覆盖层
//! - 8 个边框不透明度掩码
//!
//! 精灵表在编译时嵌入二进制，首次使用时加载并解析。
//!
//! ## 相关模块
//!
//! - [`crate::player::icon`] — 图标生成，根据玩家名称生成颜色选择
//!
//! ## 示例
//!
//! ```rust,ignore
//! use tswn_core::player::icon_render::render_icon_png_from_name;
//!
//! let png_bytes = render_icon_png_from_name("mario");
//! // png_bytes 是 16×16 RGBA PNG 的字节流
//! ```
//!
//! ## 性能说明
//!
//! - 精灵表使用 `LazyLock` 懒加载，首次调用时解析
//! - Base64 编码器为标准 RFC 4648 实现，避免额外依赖
//! - 混合算法复现 HTML Canvas `source-over` 混合模式

use std::sync::LazyLock;

use crate::player::icon::{IconResult, icon_from_name};

// ── 精灵表 ──────────────────────────────────────────────────────────────

/// 128×128 精灵表, 编译到二进制中。
static SPRITE_BYTES: &[u8] = include_bytes!("icon_sprites.png");

struct SpriteData {
    /// 38 个前景形状, 每个存储为 256 个 alpha 值 (16×16, 行主序)。
    shapes: Box<[[u8; 256]; 38]>,
    /// 8 个边框深色覆盖层 alpha 映射 (16×16)。
    borders_dark: [[u8; 256]; 8],
    /// 8 个边框不透明度掩码 (16×16) — 在所有绘制后直接替换 α。
    borders_opacity: [[u8; 256]; 8],
}

static SPRITES: LazyLock<SpriteData> = LazyLock::new(load_sprites);

fn load_sprites() -> SpriteData {
    let mut decoder = png::Decoder::new(std::io::Cursor::new(SPRITE_BYTES));
    // 精灵表使用索引颜色。展开调色板+alpha 使每个像素都是 RGBA。
    decoder.set_transformations(png::Transformations::EXPAND | png::Transformations::ALPHA);
    let mut reader = decoder.read_info().expect("icon_sprites.png is embedded and must be valid");
    let mut pixels_buf = vec![0u8; reader.output_buffer_size().expect("icon_sprites.png size must be known")];
    reader.next_frame(&mut pixels_buf).expect("icon_sprites.png frame decode failed");
    let pixels: &[u8] = &pixels_buf;
    // 图像为 128×128 RGBA → 行步长 = 128 * 4 = 512 字节。

    let mut shapes = Box::new([[0u8; 256]; 38]);
    let mut borders_dark = [[0u8; 256]; 8];
    let mut borders_opacity = [[0u8; 256]; 8];

    // 形状: q=0..37, 单元格偏移量匹配 JS tv() 函数:
    //   base = (q % 8) * 64  +  (q / 8) * 8192
    //        = col_in_sheet * (16 * 4)  +  row_in_sheet * (16 * 128 * 4)
    // Alpha = 如果 R > G 则为 R 通道, 否则为 0。
    for q in 0usize..38 {
        let base = (q % 8) * 64 + (q / 8) * 8192;
        for n in 0usize..16 {
            for l in 0usize..16 {
                let k = base + l * 4 + n * 512;
                let r = pixels[k];
                let g = pixels[k + 1];
                shapes[q][n * 16 + l] = if r > g { r } else { 0 };
            }
        }
    }

    // 边框: q=0..7, 从字节偏移量 57344 开始 (= 128px 宽图像的第 112 行)。
    //   borders_dark alpha  = 如果 R > G 则为 R, 否则为 0
    //   borders_opacity     = 如果 G > B 则为 255-G, 否则为 255
    for q in 0usize..8 {
        let base = q * 64 + 57344;
        for n in 0usize..16 {
            for l in 0usize..16 {
                let k = base + l * 4 + n * 512;
                let r = pixels[k];
                let g = pixels[k + 1];
                let b = pixels[k + 2];
                borders_dark[q][n * 16 + l] = if r > g { r } else { 0 };
                borders_opacity[q][n * 16 + l] = if g > b { 255 - g } else { 255 };
            }
        }
    }

    SpriteData {
        shapes,
        borders_dark,
        borders_opacity,
    }
}

// ── 合成 ───────────────────────────────────────────────────────────────

/// HTML Canvas `source-over` 混合: 将纯色像素合成到 `dst` 上。
#[inline]
fn blend_over(dst: &mut [u8; 4], src_rgb: [u8; 3], src_a: u8) {
    if src_a == 0 {
        return;
    }
    if src_a == 255 {
        *dst = [src_rgb[0], src_rgb[1], src_rgb[2], 255];
        return;
    }
    let sa = src_a as f32 / 255.0;
    let da = dst[3] as f32 / 255.0;
    let out_a = sa + da * (1.0 - sa);
    if out_a <= 0.0 {
        return;
    }
    let ch = |s: u8, d: u8| -> u8 { ((s as f32 * sa + d as f32 * da * (1.0 - sa)) / out_a).round() as u8 };
    dst[0] = ch(src_rgb[0], dst[0]);
    dst[1] = ch(src_rgb[1], dst[1]);
    dst[2] = ch(src_rgb[2], dst[2]);
    dst[3] = (out_a * 255.0).round() as u8;
}

/// 使用纯色在 256 像素画布上绘制 alpha 映射形状
/// (复现 JS `Sgls.o4()` 逻辑, 包括 `source-over` 混合)。
fn draw_shape(canvas: &mut [[u8; 4]; 256], alpha_map: &[u8; 256], fg: [u8; 3]) {
    for i in 0..256 {
        blend_over(&mut canvas[i], fg, alpha_map[i]);
    }
}

// ── 公共 API ────────────────────────────────────────────────────────────────

/// 将 `IconResult` 渲染为 16×16 RGBA PNG (以原始字节返回)。
pub fn render_icon_png(icon: &IconResult) -> Vec<u8> {
    let sprites = &*SPRITES;
    let mut canvas = [[0u8; 4]; 256]; // 16×16, 初始完全透明

    // 1. 用背景色填充内部 14×14 区域 (JS: fillRect(1,1,14,14))。
    let bg = icon.bg_color;
    for y in 1usize..=14 {
        for x in 1usize..=14 {
            canvas[y * 16 + x] = [bg[0], bg[1], bg[2], 255];
        }
    }

    // 2. 使用 source-over 混合模式合成每个前景形状。
    for (i, &shape_idx) in icon.shapes.iter().enumerate() {
        draw_shape(&mut canvas, &sprites.shapes[shape_idx], icon.fg_colors[i]);
    }

    // 3. 绘制深色边框覆盖层 (颜色 [64, 64, 64])。
    draw_shape(&mut canvas, &sprites.borders_dark[icon.border_style], [64, 64, 64]);

    // 4. 应用边框不透明度掩码 — 直接替换 alpha (JS: pixels[p*4+3] = r[p])。
    //    如果 alpha 变为 0, 也将 RGB 清零 (匹配 JS canvas 预乘 alpha 行为)。
    let border_opacity = &sprites.borders_opacity[icon.border_style];
    for p in 0..256 {
        canvas[p][3] = border_opacity[p];
        if canvas[p][3] == 0 {
            canvas[p][0] = 0;
            canvas[p][1] = 0;
            canvas[p][2] = 0;
        }
    }

    // 5. 编码为 16×16 RGBA PNG。
    let flat: Vec<u8> = canvas.iter().flat_map(|&px| px).collect();
    let mut out = Vec::new();
    let mut encoder = png::Encoder::new(&mut out, 16, 16);
    encoder.set_color(png::ColorType::Rgba);
    encoder.set_depth(png::BitDepth::Eight);
    encoder
        .write_header()
        .and_then(|mut w| w.write_image_data(&flat))
        .expect("PNG encoding should never fail for a valid image");
    out
}

/// 将图标渲染为 base64 data URL (`data:image/png;base64,...`),
/// 匹配 JS `canvas.toDataURL("image/png")` 的输出。
pub fn render_icon_b64(icon: &IconResult) -> String {
    let png = render_icon_png(icon);
    format!("data:image/png;base64,{}", base64_encode(&png))
}

/// 便捷包装器: 通过玩家名称渲染 → PNG 字节。
pub fn render_icon_png_from_name(name: &str) -> Vec<u8> { render_icon_png(&icon_from_name(name)) }

/// 便捷包装器: 通过玩家名称渲染 → base64 data URL。
pub fn render_icon_b64_from_name(name: &str) -> String { render_icon_b64(&icon_from_name(name)) }

// ── 内部辅助函数 ──────────────────────────────────────────────────────────

/// 标准 RFC 4648 base64 编码器 — 避免额外的 crate 依赖。
fn base64_encode(data: &[u8]) -> String {
    const TABLE: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    let mut out = String::with_capacity(data.len().div_ceil(3) * 4);
    for chunk in data.chunks(3) {
        let b0 = chunk[0] as usize;
        let b1 = if chunk.len() > 1 { chunk[1] as usize } else { 0 };
        let b2 = if chunk.len() > 2 { chunk[2] as usize } else { 0 };
        let n = (b0 << 16) | (b1 << 8) | b2;
        out.push(TABLE[(n >> 18) & 63] as char);
        out.push(TABLE[(n >> 12) & 63] as char);
        out.push(if chunk.len() > 1 { TABLE[(n >> 6) & 63] as char } else { '=' });
        out.push(if chunk.len() > 2 { TABLE[n & 63] as char } else { '=' });
    }
    out
}

